import { Component, OnInit } from '@angular/core';
import { MagicService } from '../../services/magic.service';
import { Magic } from '../../models/magic';
import { Router } from '@angular/router';
import { MagicDetail, School, MagicClass } from '../../models/magic-detail';

@Component({
  selector: 'app-magias',
  templateUrl: './magias.component.html',
  styleUrls: ['./magias.component.css']
})
export class MagiasComponent implements OnInit {
  magias!: { count: number, results: MagicDetailComponent[] };
  loading: boolean = true;
  error: string = '';

  filteredClass: MagicClass | null = null; // Filtro por classe
  filteredSchool: School | null = null; // Filtro por escola
  uniqueClasses: MagicClass[] = []; // Lista de classes únicas para o filtro
  uniqueSchools: School[] = []; // Lista de escolas únicas para o filtro

  constructor(private magicService: MagicService,
              private router: Router) {}

  ngOnInit(): void {
    this.magicService.getMagics().subscribe({
      next: (data) => {
        this.magias = data;
        this.loading = false;

        // Carregar classes e escolas únicas para os filtros
        this.extractUniqueClassesAndSchools();
      },
      error: (err) => {
        this.error = 'Erro ao carregar as magias.';
        this.loading = false;
      }
    });
  }

  goToDetail(index: string): void {
    this.router.navigate(['/magias', index]);
  }

  // Extrai classes e escolas únicas a partir das magias
  extractUniqueClassesAndSchools() {
    const classSet = new Set<string>();
    const schoolSet = new Set<string>();

    this.magias.results.forEach(magia => {
      magia.classes?.forEach((magicClass: MagicClass) => {
        if (!classSet.has(magicClass.name)) {
          classSet.add(magicClass.name);
          this.uniqueClasses.push(magicClass);
        }
      });

      if (magia.school && !schoolSet.has(magia.school.name)) {
        schoolSet.add(magia.school.name);
        this.uniqueSchools.push(magia.school);
      }
    });
  }

  // Filtra por classe
  filterByClass(magicClass: MagicClass) {
    this.filteredClass = magicClass;
    this.filteredSchool = null; // Reseta filtro de escola
  }

  // Filtra por escola
  filterBySchool(school: School) {
    this.filteredSchool = school;
    this.filteredClass = null; // Reseta filtro de classe
  }

  // Limpa os filtros
  clearFilters() {
    this.filteredClass = null;
    this.filteredSchool = null;
  }

  // Retorna as magias filtradas
  filteredMagias() {
    return this.magias.results.filter(magia => {
      const matchesClass = this.filteredClass ? magia.classes.some(c => c.name === this.filteredClass?.name) : true;
      const matchesSchool = this.filteredSchool ? magia.school.name === this.filteredSchool.name : true;
      return matchesClass && matchesSchool;
    });
  }
}
